// Basic C++ Program Structure
#include <iostream>  // Include input/output stream header

// Using std namespace to avoid std:: prefix
using namespace std;

// Main function - entry point of every C++ program
int main() {
    // Declare variables
    int number;

    // Display prompt to user using cout (stream insertion)
    cout << "Enter a number: ";

    // Read input from user using cin (stream extraction)
    cin >> number;

    // Display the entered number
    cout << "You entered: " << number << endl;

    // Return 0 to indicate successful execution
    return 0;
}

// Program to demonstrate command-line arguments
#include <iostream>
#include <cstdlib>  // For atoi or use stoi from string

using namespace std;

int main(int argc, char* argv[]) {
    // argc: number of arguments including program name
    // argv: array of character pointers (strings)

    // Check if sufficient arguments provided
    if (argc != 3) {
        cerr << "Error: Please provide two numbers" << endl;
        cerr << "Usage: " << argv[0] << " <num1> <num2>" << endl;
        return 1;  // Return non-zero for error
    }

    // Convert string arguments to integers
    int num1 = atoi(argv[1]);
    int num2 = atoi(argv[2]);

    // Perform addition
    int sum = num1 + num2;

    // Display result
    cout << "Sum of " << num1 << " and " << num2 
         << " is: " << sum << endl;

    return 0;  // Successful execution
}

