// Program demonstrating different output streams
#include <iostream>
#include <fstream>

using namespace std;

int main() {
    int age;

    cout << "Enter your age: ";
    cin >> age;

    // Validate input using cerr for errors
    if (age < 0) {
        // cerr - unbuffered, immediate output to stderr
        cerr << "Error: Age cannot be negative!" << endl;
        return 1;
    }

    if (age > 150) {
        cerr << "Error: Invalid age entered!" << endl;
        return 1;
    }

    // clog - buffered, for logging purposes
    clog << "Log: Valid age input received: " << age << endl;

    // Normal output to stdout
    cout << "Your age is: " << age << endl;
    cout << "In 10 years, you will be " << (age + 10) << endl;

    return 0;
}

// Demonstrating namespace usage in C++
#include <iostream>
#include <string>

// Method 1: Using 'using namespace std' (not recommended for large projects)
// using namespace std;

// Method 2: Using std:: prefix (recommended)

int main() {
    // Using std:: prefix for individual names
    std::cout << "=== Namespace Demonstration ===" << std::endl;

    // String input/output
    std::string name;
    std::cout << "Enter your name: ";
    std::getline(std::cin, name);

    // Integer input/output
    int age;
    std::cout << "Enter your age: ";
    std::cin >> age;

    // Display using std::endl for newline
    std::cout << "\nHello, " << name << "!" << std::endl;
    std::cout << "You are " << age << " years old." << std::endl;

    // Using std::string methods
    std::cout << "Your name has " << name.length() << " characters." << std::endl;

    return 0;
}

/* Note: Both methods work. Using std:: prefix is preferred in:
   - Large projects to avoid name collisions
   - Header files to prevent polluting user's namespace
   - When mixing multiple libraries

   'using namespace std;' is acceptable in small programs and
   learning exercises but should be avoided in production code. */
